const body = $input.first().json.body || $input.first().json;
const trace_id = body.trace_id || ('trace-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9));
return [{ json: {
  trace_id,
  question: (body.question || '').trim(),
  mode: (body.mode || '').toLowerCase().trim(),
  student_answer: (body.student_answer || body.answer || '').trim(),
  topic: (body.topic || '').trim(),
  running_score: (typeof body.running_score === 'number') ? body.running_score : 0
}}];

const data = $input.first().json;
const { question, mode } = data;
const validModes = ['explain', 'quiz', 'evaluate'];
const injectionPatterns = [
  'ignore previous instructions', 'reveal system prompt',
  'do not use sources', 'change my score', 'bypass safety',
  'ignore all instructions', 'disregard previous', 'jailbreak'
];
const q = (question || '').toLowerCase();
if (!question && mode !== 'evaluate') {
  return [{ json: { ...data, safe: false, error_type: 'empty_question' } }];
}
if (!validModes.includes(mode)) {
  return [{ json: { ...data, safe: false, error_type: 'invalid_mode' } }];
}
const injectionFound = injectionPatterns.some(function(p) { return q.includes(p); });
if (injectionFound) {
  return [{ json: { ...data, safe: false, error_type: 'injection_attempt' } }];
}
return [{ json: { ...data, safe: true } }];

const data = $input.first().json;
const messages = {
  empty_question: 'Question cannot be empty.',
  invalid_mode: 'Invalid mode. Supported: explain, quiz, evaluate.',
  injection_attempt: 'Request blocked by safety filter.'
};
return [{ json: {
  trace_id: data.trace_id,
  status: 'rejected',
  error: data.error_type,
  message: messages[data.error_type] || 'Request rejected.'
}}];

const data = $input.first().json;
const llm = data.llm_output || {};
const mode = data.mode;
const sources = data.sources || [];
const response = { trace_id: data.trace_id, status: 'success', mode, progress: { saved: !!data.progress_saved } };
if (mode === 'explain') {
  response.answer = { explanation: llm.explanation || '', example: llm.example || '', sources };
  response.quiz = llm.quiz || [];
  response.recommendation = llm.recommendation || '';
} else if (mode === 'quiz') {
  response.quiz = llm.quiz || [];
  response.answer = { sources };
  response.recommendation = '';
} else if (mode === 'evaluate') {
  response.evaluation = { correct: llm.correct || false, partial_credit: llm.partial_credit || false, score: llm.score || 0, feedback: llm.feedback || '', correct_answer: llm.correct_answer || '' };
  response.answer = { sources };
  response.recommendation = llm.recommendation || '';
}
return [{ json: response }];
